export interface FilterState {
  evaluation: string;
  year: string;
  network: string;
}

export interface ParticipationData {
  rate: number;
  predicted: number;
  present: number;
  effective: number;
}

export interface StudentProfile {
  name: string;
  count: number;
  percentage: number;
  color: string;
  level?: number; // 0 for total, 1-4 for specific levels
}

export interface MetricDetail {
  category: string;
  label: string;
  icon: 'book' | 'clock' | 'target' | 'lightbulb';
  preReader: string | number;
  beginner: string | number;
  fluent: string | number;
  max?: number; // For "X out of Y" display
}

export enum AnalysisStatus {
  IDLE = 'IDLE',
  LOADING = 'LOADING',
  SUCCESS = 'SUCCESS',
  ERROR = 'ERROR'
}

import { GoogleGenAI } from "@google/genai";
import { ParticipationData, StudentProfile } from "../types";

const apiKey = process.env.API_KEY || '';

// Safely initialize the client only if key exists, otherwise we handle it in the UI
const ai = apiKey ? new GoogleGenAI({ apiKey }) : null;

export const generatePedagogicalInsights = async (
  participation: ParticipationData,
  profiles: StudentProfile[]
): Promise<string> => {
  if (!ai) {
    throw new Error("API Key not configured");
  }

  const prompt = `
    Atue como um Especialista em Dados Educacionais e Pedagogo Sênior.
    Analise os seguintes dados da 'Avaliação de Fluência Leitora 2025':

    1. Participação:
    - Taxa: ${participation.rate}%
    - Previstos: ${participation.predicted}
    - Presentes: ${participation.present}

    2. Perfil dos Estudantes:
    ${profiles.map(p => `- ${p.name}: ${p.count} estudantes (${p.percentage}%)`).join('\n')}

    Tarefa:
    Forneça uma análise qualitativa curta e objetiva (máximo 2 parágrafos) sobre:
    1. A eficácia da adesão (participação).
    2. O cenário de alfabetização baseado na distribuição dos perfis (Pré-leitor vs Leitor Iniciante vs Fluente).
    3. Uma recomendação pedagógica prioritária para a rede de ensino focar nos alunos 'Pré-leitores'.

    Formate a resposta em Markdown.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        thinkingConfig: { thinkingBudget: 0 } // Speed over deep reasoning for this summary
      }
    });

    return response.text || "Não foi possível gerar a análise no momento.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

