              <th className="px-6 py-4 bg-gray-50 text-gray-500 font-bold border-b border-gray-200 w-1/3">Indicador</th>
              <th className="px-6 py-4 bg-cyan-200 text-cyan-900 text-center w-1/5">Pré-leitor</th>
              <th className="px-6 py-4 bg-cyan-500 text-white text-center w-1/5">Leitor Iniciante</th>
              <th className="px-6 py-4 bg-blue-600 text-white text-center w-1/5">Leitor Fluente</th>
            </tr>
          </thead>
          <tbody>
            {metrics.map((metric, index) => {
              const Icon = IconMap[metric.icon];
              return (
                <tr key={index} className="bg-white border-b border-gray-100 hover:bg-gray-50">
                  <td className="px-6 py-6 font-medium text-gray-900">
                    <div className="flex flex-col gap-1">
                      <span className="text-xs text-gray-400 uppercase tracking-wider">{metric.category}</span>
                      <span>{metric.label}</span>
