                    const value = metric[key as keyof MetricDetail];
                    const isApplicable = value !== 'N/A';

                    return (
                      <td key={key} className="px-6 py-4 text-center">
                        <div className="flex flex-col items-center justify-center gap-2">
                          <Icon className={`w-6 h-6 ${isApplicable ? 'text-gray-700' : 'text-gray-300'}`} />
