                            </span>
                          )}
                        </div>
                      </td>
                    );
                  })}
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default MetricsTable;

import React, { useState } from 'react';
import { Sparkles, RefreshCcw, AlertCircle } from 'lucide-react';
import { generatePedagogicalInsights } from '../services/geminiService';
import { ParticipationData, StudentProfile, AnalysisStatus } from '../types';

interface GeminiInsightsProps {
  participation: ParticipationData;
  profiles: StudentProfile[];
}

const GeminiInsights: React.FC<GeminiInsightsProps> = ({ participation, profiles }) => {
  const [status, setStatus] = useState<AnalysisStatus>(AnalysisStatus.IDLE);
  const [insight, setInsight] = useState<string>("");
  const [error, setError] = useState<string>("");

  const handleGenerate = async () => {
    setStatus(AnalysisStatus.LOADING);
    setError("");
    try {
      const result = await generatePedagogicalInsights(participation, profiles);
      setInsight(result);
      setStatus(AnalysisStatus.SUCCESS);
    } catch (e) {
      setError("Não foi possível conectar ao assistente inteligente. Verifique sua chave de API.");
      setStatus(AnalysisStatus.ERROR);
    }
  };

  return (
    <div className="bg-gradient-to-r from-indigo-50 to-blue-50 rounded-xl shadow-sm border border-indigo-100 p-6 mb-8">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-1.5 rounded-lg">
            <Sparkles className="w-5 h-5 text-white" />
          </div>
          <h3 className="text-lg font-bold text-indigo-900">Assistente Pedagógico IA</h3>
        </div>

        {status === AnalysisStatus.IDLE || status === AnalysisStatus.ERROR || status === AnalysisStatus.SUCCESS ? (
          <button 
            onClick={handleGenerate}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-medium rounded-lg transition-colors shadow-sm"
          >
            {status === AnalysisStatus.IDLE ? 'Gerar Análise' : 'Atualizar Análise'}
          </button>
        ) : (
          <button disabled className="flex items-center gap-2 px-4 py-2 bg-indigo-400 text-white text-sm font-medium rounded-lg cursor-not-allowed">
            <RefreshCcw className="w-4 h-4 animate-spin" />
            Analisando...
          </button>
        )}
      </div>

      {status === AnalysisStatus.IDLE && (
        <p className="text-sm text-indigo-700">
          Clique em "Gerar Análise" para receber insights automáticos sobre os dados apresentados, utilizando a inteligência do Google Gemini.
        </p>
      )}

      {status === AnalysisStatus.ERROR && (
        <div className="flex items-start gap-2 bg-red-50 p-4 rounded-lg border border-red-100 text-red-700 text-sm">
          <AlertCircle className="w-5 h-5 shrink-0" />
          <p>{error}</p>
        </div>
      )}

      {status === AnalysisStatus.SUCCESS && (
        <div className="bg-white/80 p-5 rounded-lg border border-indigo-100 text-gray-800 text-sm leading-relaxed whitespace-pre-line shadow-inner">
           {/* Rendering markdown-like bolding simply for this demo */}
           {insight.split('**').map((part, i) => 
             i % 2 === 1 ? <strong key={i} className="text-indigo-900">{part}</strong> : part
           )}
        </div>
      )}
    </div>
  );
};

export default GeminiInsights;

