import React, { useMemo } from 'react';
import { X, TrendingUp, Trophy, ArrowUpRight } from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  ReferenceDot
} from 'recharts';
import { StudentProfile } from '../types';

interface CrossAnalysisModalProps {
  isOpen: boolean;
  onClose: () => void;
  municipalData: StudentProfile[];
  regionalData: StudentProfile[];
}

const CrossAnalysisModal: React.FC<CrossAnalysisModalProps> = ({
  isOpen,
  onClose,
  municipalData,
  regionalData,
}) => {
  if (!isOpen) return null;

  // Process data for the chart
  const chartData = useMemo(() => {
    return municipalData.map((mItem, index) => {
      const rItem = regionalData.find(r => r.name === mItem.name) || regionalData[index];
      return {
        name: mItem.name.replace('Pré-leitor ', 'PL ').replace('Leitor ', ''), // Shorten names for X-Axis
        fullName: mItem.name,
        Municipal: mItem.percentage,
        Regional: rItem.percentage,
        diff: mItem.percentage - rItem.percentage
      };
    });
  }, [municipalData, regionalData]);

  // Identify highlights (where Municipal > Regional)
  // We prioritize "Leitor Fluente", "Leitor Iniciante" and reductions in "Pré-leitor Total"
  // But generally, let's show where the percentage is higher for positive categories, 
  // and for "Pré-leitor" we usually want lower, but the prompt asks where it "surpassed in indices".
  // Usually in education, surpassing index in "Fluent" is good, surpassing in "Pre-reader" is bad.
  // However, to keep it simple based on the prompt "superou em indices", we will highlight absolute higher numbers
  // OR contextually good numbers. Let's assume Higher % in Fluent/Beginner is good, Lower % in Pre-reader is good.

  const highlights = useMemo(() => {
    const wins: { category: string; value: number; diff: number; isPositiveContext: boolean }[] = [];

    chartData.forEach(d => {
      const isPositiveMetric = d.fullName.includes('Fluente') || d.fullName.includes('Iniciante');
      const isNegativeMetric = d.fullName.includes('Pré-leitor');

      if (isPositiveMetric && d.Municipal > d.Regional) {
        wins.push({ category: d.fullName, value: d.Municipal, diff: d.diff, isPositiveContext: true });
      } else if (isNegativeMetric && d.Municipal < d.Regional) {
        // Technically a "win" for the municipality if they have fewer pre-readers than the region
         wins.push({ category: d.fullName, value: d.Municipal, diff: Math.abs(d.diff), isPositiveContext: true });
      }
    });
    return wins;
  }, [chartData]);

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-gray-900/50 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      ></div>

      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-5xl max-h-[90vh] overflow-y-auto flex flex-col animate-in fade-in zoom-in duration-200">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100 sticky top-0 bg-white z-10">
          <div className="flex items-center gap-3">
            <div className="bg-blue-100 p-2 rounded-lg">
              <TrendingUp className="w-6 h-6 text-blue-700" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-gray-900">Análise Cruzada: Município vs. Regional</h2>
              <p className="text-sm text-gray-500">Comparativo direto de desempenho por nível de proficiência</p>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6 space-y-8">
          {/* Highlights Section */}
          <section>
            <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide mb-4 flex items-center gap-2">
              <Trophy className="w-4 h-4 text-yellow-500" />
              Destaques do Município
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {highlights.length > 0 ? (
                highlights.map((win, idx) => (
                  <div key={idx} className="bg-gradient-to-br from-green-50 to-emerald-50 border border-green-100 p-4 rounded-xl flex flex-col justify-between">
                    <div>
                      <div className="text-green-800 font-bold text-sm mb-1">{win.category}</div>
                      <div className="text-xs text-green-600 mb-3">Performance superior à média regional</div>
                    </div>
                    <div className="flex items-end justify-between">
                      <div className="text-2xl font-bold text-green-700">{win.value.toFixed(1)}%</div>
                      <div className="flex items-center text-xs font-bold text-green-600 bg-white px-2 py-1 rounded-full shadow-sm">
                        <ArrowUpRight className="w-3 h-3 mr-1" />
                        {win.category.includes('Pré-leitor') ? '-' : '+'}{win.diff.toFixed(1)} p.p.
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="col-span-3 text-center py-4 text-gray-500 bg-gray-50 rounded-lg text-sm">
                  Nenhum destaque positivo significativo identificado em relação à regional neste cenário.
                </div>
              )}
            </div>
          </section>

          {/* Chart Section */}
          <section className="bg-white border border-gray-100 rounded-xl p-6 shadow-sm">
             <div className="mb-6">
                <h3 className="text-lg font-bold text-gray-900">Curva de Proficiência Comparada</h3>
                <p className="text-sm text-gray-500">
                  Visualização linear da distribuição dos estudantes. A linha <span className="text-blue-600 font-bold">Azul</span> representa o Município e a <span className="text-gray-400 font-bold">Cinza</span> a Regional.
                </p>
             </div>

             <div className="h-[400px] w-full">
               <ResponsiveContainer width="100%" height="100%">
                 <LineChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                   <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                   <XAxis 
                      dataKey="name" 
                      tick={{fill: '#6b7280', fontSize: 12}} 
                      axisLine={false}
                      tickLine={false}
                      dy={10}
                   />
                   <YAxis 
                      tick={{fill: '#6b7280', fontSize: 12}} 
                      axisLine={false}
                      tickLine={false}
                      unit="%"
                   />
                   <Tooltip 
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                      formatter={(value: number) => [`${value.toFixed(1)}%`, '']}
                      labelStyle={{ color: '#374151', fontWeight: 'bold', marginBottom: '0.5rem' }}
                   />
                   <Legend wrapperStyle={{ paddingTop: '20px' }} />

                   <Line 
                      type="monotone" 
                      dataKey="Regional" 
                      stroke="#9ca3af" 
                      strokeWidth={2} 
                      dot={{ r: 4, fill: '#9ca3af' }}
                      activeDot={{ r: 6 }}
                      strokeDasharray="5 5"
                   />
                   <Line 
                      type="monotone" 
                      dataKey="Municipal" 
                      stroke="#2563eb" 
                      strokeWidth={3} 
                      dot={{ r: 6, fill: '#2563eb', strokeWidth: 2, stroke: '#fff' }}
                      activeDot={{ r: 8 }}
                   />
                 </LineChart>
               </ResponsiveContainer>
             </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default CrossAnalysisModal;

