import React, { useMemo } from 'react';
import { X, TrendingUp, Trophy, ArrowUpRight, ArrowDownRight, AlertTriangle } from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import { StudentProfile } from '../types';

interface CrossAnalysisModalProps {
  isOpen: boolean;
  onClose: () => void;
  municipalData: StudentProfile[];
  regionalData: StudentProfile[];
}

const CrossAnalysisModal: React.FC<CrossAnalysisModalProps> = ({
  isOpen,
  onClose,
  municipalData,
  regionalData,
}) => {
  if (!isOpen) return null;

  // Process data for the chart
  const chartData = useMemo(() => {
    return municipalData.map((mItem, index) => {
      const rItem = regionalData.find(r => r.name === mItem.name) || regionalData[index];
      return {
        name: mItem.name.replace('Pré-leitor ', 'PL ').replace('Leitor ', ''), // Shorten names for X-Axis
        fullName: mItem.name,
        Municipal: mItem.percentage,
        Regional: rItem.percentage,
        diff: mItem.percentage - rItem.percentage
      };
    });
  }, [municipalData, regionalData]);

  // Separate analysis into Highlights (Good) and Alerts (Bad/Attention)
  const analysis = useMemo(() => {
    const highlights: { category: string; value: number; diff: number; description: string }[] = [];
    const alerts: { category: string; value: number; diff: number; description: string }[] = [];

    chartData.forEach(d => {
      const isPreReader = d.fullName.includes('Pré-leitor');
      const diffVal = parseFloat(Math.abs(d.diff).toFixed(1));

      // Skip very small differences to avoid noise
      if (diffVal < 0.1) return;

      if (isPreReader) {
        // LOGIC FOR PRE-READERS
        if (d.Municipal > d.Regional) {
          // BAD: Municipal has MORE pre-readers than regional
          alerts.push({
            category: d.fullName,
            value: d.Municipal,
            diff: diffVal,
            description: `Índice ${diffVal} p.p. acima da média regional`
          });
        } else {
          // GOOD: Municipal has FEWER pre-readers than regional
          highlights.push({
            category: d.fullName,
            value: d.Municipal,
            diff: diffVal,
            description: `Índice ${diffVal} p.p. abaixo da média regional`
          });
        }
      } else {
        // LOGIC FOR FLUENT / BEGINNER
        if (d.Municipal > d.Regional) {
          // GOOD: Municipal has MORE fluent/beginner readers
          highlights.push({
            category: d.fullName,
            value: d.Municipal,
            diff: diffVal,
            description: `Performance ${diffVal} p.p. superior à regional`
          });
        } 
        // We could add alerts for low fluency here, but the prompt emphasized Pre-readers for alerts.
      }
    });

    return { highlights, alerts };
  }, [chartData]);

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 sm:p-6">
      <div 
        className="absolute inset-0 bg-gray-900/50 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      ></div>

      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-5xl max-h-[90vh] overflow-y-auto flex flex-col animate-in fade-in zoom-in duration-200">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100 sticky top-0 bg-white z-10">
          <div className="flex items-center gap-3">
            <div className="bg-blue-100 p-2 rounded-lg">
              <TrendingUp className="w-6 h-6 text-blue-700" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-gray-900">Análise Cruzada: Município vs. Regional</h2>
              <p className="text-sm text-gray-500">Comparativo direto de desempenho por nível de proficiência</p>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6 space-y-8">
          {/* Alerts Section - Show this FIRST if there are issues */}
          {analysis.alerts.length > 0 && (
            <section>
              <h3 className="text-sm font-bold text-red-600 uppercase tracking-wide mb-4 flex items-center gap-2">
                <AlertTriangle className="w-4 h-4" />
                Pontos de Atenção (Índices Superiores à Regional)
              </h3>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                {analysis.alerts.map((alert, idx) => (
                  <div key={idx} className="bg-red-50 border border-red-100 p-4 rounded-xl flex flex-col justify-between">
                    <div>
                      <div className="text-red-800 font-bold text-sm mb-1">{alert.category}</div>
                      <div className="text-xs text-red-600 mb-3">{alert.description}</div>
                    </div>
                    <div className="flex items-end justify-between">
                      <div className="text-2xl font-bold text-red-700">{alert.value.toFixed(1)}%</div>
                      <div className="flex items-center text-xs font-bold text-red-600 bg-white px-2 py-1 rounded-full shadow-sm border border-red-100">
                        <ArrowUpRight className="w-3 h-3 mr-1" />
                        +{alert.diff.toFixed(1)} p.p.
                      </div>
                    </div>
                  </div>
                ))}
              </div>
              <p className="text-xs text-gray-500 mt-2 italic">
                * Para os níveis de pré-leitor, um índice superior à média regional indica necessidade de intervenção pedagógica prioritária.
              </p>
            </section>
          )}

          {/* Highlights Section */}
          <section>
            <h3 className="text-sm font-bold text-emerald-600 uppercase tracking-wide mb-4 flex items-center gap-2">
              <Trophy className="w-4 h-4 text-emerald-500" />
              Destaques Positivos (Superando Metas Regionais)
            </h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
              {analysis.highlights.length > 0 ? (
                analysis.highlights.map((win, idx) => (
                  <div key={idx} className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl flex flex-col justify-between">
                    <div>
                      <div className="text-emerald-800 font-bold text-sm mb-1">{win.category}</div>
                      <div className="text-xs text-emerald-600 mb-3">{win.description}</div>
                    </div>
                    <div className="flex items-end justify-between">
                      <div className="text-2xl font-bold text-emerald-700">{win.value.toFixed(1)}%</div>
                      <div className="flex items-center text-xs font-bold text-emerald-600 bg-white px-2 py-1 rounded-full shadow-sm border border-emerald-100">
                        {win.category.includes('Pré-leitor') ? <ArrowDownRight className="w-3 h-3 mr-1" /> : <ArrowUpRight className="w-3 h-3 mr-1" />}
                        {win.category.includes('Pré-leitor') ? '-' : '+'}{win.diff.toFixed(1)} p.p.
                      </div>
                    </div>
                  </div>
                ))
              ) : (
                <div className="col-span-3 text-center py-4 text-gray-500 bg-gray-50 rounded-lg text-sm border border-dashed border-gray-200">
                  Nenhum índice positivo significativo identificado em relação à regional neste cenário.
                </div>
              )}
            </div>
          </section>

          {/* Chart Section */}
          <section className="bg-white border border-gray-100 rounded-xl p-6 shadow-sm">
             <div className="mb-6">
                <h3 className="text-lg font-bold text-gray-900">Curva de Proficiência Comparada</h3>
                <p className="text-sm text-gray-500">
                  Comparativo linear. <span className="text-blue-600 font-bold">Azul (Município)</span> acima da <span className="text-gray-400 font-bold">Cinza (Regional)</span> é positivo para Fluentes, mas negativo para Pré-leitores.
                </p>
             </div>

             <div className="h-[400px] w-full">
               <ResponsiveContainer width="100%" height="100%">
                 <LineChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                   <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                   <XAxis 
                      dataKey="name" 
                      tick={{fill: '#6b7280', fontSize: 12}} 
                      axisLine={false}
                      tickLine={false}
                      dy={10}
                   />
                   <YAxis 
                      tick={{fill: '#6b7280', fontSize: 12}} 
                      axisLine={false}
                      tickLine={false}
                      unit="%"
                   />
                   <Tooltip 
                      contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)' }}
                      formatter={(value: number) => [`${value.toFixed(1)}%`, '']}
                      labelStyle={{ color: '#374151', fontWeight: 'bold', marginBottom: '0.5rem' }}
                   />
                   <Legend wrapperStyle={{ paddingTop: '20px' }} />

                   <Line 
                      type="monotone" 
                      dataKey="Regional" 
                      stroke="#9ca3af" 
                      strokeWidth={2} 
                      dot={{ r: 4, fill: '#9ca3af' }}
                      activeDot={{ r: 6 }}
                      strokeDasharray="5 5"
                   />
                   <Line 
                      type="monotone" 
                      dataKey="Municipal" 
                      stroke="#2563eb" 
                      strokeWidth={3} 
                      dot={{ r: 6, fill: '#2563eb', strokeWidth: 2, stroke: '#fff' }}
                      activeDot={{ r: 8 }}
                   />
                 </LineChart>
               </ResponsiveContainer>
             </div>
          </section>
        </div>
      </div>
    </div>
  );
};

export default CrossAnalysisModal;

