import React, { useMemo } from 'react';
import { X, TrendingUp, Trophy, ArrowUpRight, ArrowDownRight, AlertTriangle, Calculator, ShieldCheck } from 'lucide-react';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
} from 'recharts';
import { StudentProfile } from '../types';

interface CrossAnalysisModalProps {
  isOpen: boolean;
  onClose: () => void;
  municipalData: StudentProfile[];
  regionalData: StudentProfile[];
}

const CrossAnalysisModal: React.FC<CrossAnalysisModalProps> = ({
  isOpen,
  onClose,
  municipalData,
  regionalData,
}) => {
  if (!isOpen) return null;

  // --- IFL CALCULATION LOGIC ---
  // Formula: (N1*0 + N2*1 + N3*2.5 + N4*4 + Inic*6 + Fluente*10) / 100
  const calculateIFL = (data: StudentProfile[]) => {
    const getVal = (namePart: string) => data.find(d => d.name.includes(namePart))?.percentage || 0;

    const n1 = getVal('Nível 1');
    const n2 = getVal('Nível 2');
    const n3 = getVal('Nível 3');
    const n4 = getVal('Nível 4');
    const inic = getVal('Iniciante');
    const fluent = getVal('Fluente');

    const score = (n1 * 0) + (n2 * 1) + (n3 * 2.5) + (n4 * 4) + (inic * 6) + (fluent * 10);
    return score / 100; // Normalizing to 0-10 scale
  };

  const municipalIFL = calculateIFL(municipalData);
  const regionalIFL = calculateIFL(regionalData);

  // Process data for the chart
  const chartData = useMemo(() => {
    return municipalData.map((mItem, index) => {
      const rItem = regionalData.find(r => r.name === mItem.name) || regionalData[index];
      return {
        name: mItem.name.replace('Pré-leitor ', 'PL ').replace('Leitor ', ''),
        fullName: mItem.name,
        Municipal: mItem.percentage,
        Regional: rItem.percentage,
        diff: mItem.percentage - rItem.percentage
      };
    });
  }, [municipalData, regionalData]);

  // --- ANALYSIS LOGIC (Redução de Déficit) ---
  const analysis = useMemo(() => {
    const highlights: { category: string; value: number; diff: number; description: string; isReduction: boolean }[] = [];
    const alerts: { category: string; value: number; diff: number; description: string }[] = [];
    let criticalWarning = false;

    chartData.forEach(d => {
      const isCriticalLevel = d.fullName.includes('Nível 1') || d.fullName.includes('Nível 2') || d.fullName === 'Pré-leitor Total';
      const isFluency = d.fullName.includes('Fluente') || d.fullName.includes('Iniciante');
      const diffVal = parseFloat(Math.abs(d.diff).toFixed(1));

      // Skip negligible differences
      if (diffVal < 0.1) return;

      if (isCriticalLevel) {
        // "More is Less" Logic
        if (d.Municipal > d.Regional) {
          // BAD: Municipal has HIGHER critical deficit
          alerts.push({
            category: d.fullName,
            value: d.Municipal,
            diff: diffVal,
            description: `Déficit ${diffVal}% superior à regional`
          });
          criticalWarning = true;
        } else {
          // GOOD: Municipal REDUCED deficit
          highlights.push({
            category: d.fullName,
            value: d.Municipal,
            diff: diffVal,
            description: `Redução positiva de ${diffVal}%`,
            isReduction: true
          });
        }
      } else if (isFluency) {
        // Standard "More is Better" Logic
        if (d.Municipal > d.Regional) {
          highlights.push({
            category: d.fullName,
            value: d.Municipal,
            diff: diffVal,
            description: `Superavit de ${diffVal}%`,
            isReduction: false
          });
        } else {
            // Optional: Alert for lower fluency if strictly needed, but prompt focused on Critical Levels for Alerts
        }
      }
    });

    return { highlights, alerts, criticalWarning };
  }, [chartData]);

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 sm:p-6 font-sans">
      <div 
        className="absolute inset-0 bg-gray-900/60 backdrop-blur-sm transition-opacity" 
        onClick={onClose}
      ></div>

      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-6xl max-h-[95vh] overflow-y-auto flex flex-col animate-in fade-in zoom-in duration-200">
        {/* Header */}
        <div className="flex items-center justify-between p-6 border-b border-gray-100 sticky top-0 bg-white z-10">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-lg shadow-blue-200">
              <TrendingUp className="w-6 h-6 text-white" />
            </div>
            <div>
              <h2 className="text-xl font-bold text-gray-900">Módulo de Análise Cruzada</h2>
              <p className="text-sm text-gray-500">Comparativo de Eficiência e Redução de Déficit</p>
            </div>
          </div>
          <button 
            onClick={onClose}
            className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="p-6 space-y-8 bg-gray-50/50">

          {/* Top Row: IFL Scoreboard & Critical Alert */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
            {/* IFL Card */}
            <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm flex flex-col justify-between">
              <div className="flex items-center gap-2 mb-4">
                <Calculator className="w-5 h-5 text-indigo-600" />
                <h3 className="font-bold text-gray-700">IFL Comparativo (0-10)</h3>
              </div>
              <div className="flex items-end justify-between px-2">
                <div className="text-center">
                  <div className="text-sm text-gray-500 mb-1">Município</div>
                  <div className="text-4xl font-extrabold text-blue-600">{municipalIFL.toFixed(2)}</div>
                </div>
                <div className="text-gray-300 font-light text-3xl mb-1">vs</div>
                <div className="text-center">
                  <div className="text-sm text-gray-500 mb-1">Regional</div>
                  <div className="text-4xl font-extrabold text-gray-400">{regionalIFL.toFixed(2)}</div>
                </div>
              </div>
              <div className="mt-4 pt-4 border-t border-gray-100 text-xs text-center text-gray-400">
                Índice de Fluência Leitora Ponderado
              </div>
            </div>

            {/* Critical Alert Logic */}
            <div className="lg:col-span-2">
              {analysis.criticalWarning ? (
                <div className="bg-red-50 border-l-4 border-red-500 p-6 rounded-r-xl h-full shadow-sm flex items-start gap-4">
                  <div className="bg-red-100 p-3 rounded-full shrink-0">
                    <AlertTriangle className="w-8 h-8 text-red-600" />
                  </div>
                  <div>
                    <h3 className="text-lg font-bold text-red-800 mb-2">Atenção: Indicadores Críticos Elevados</h3>
                    <p className="text-red-700 leading-relaxed">
                      O Município apresenta um índice de alunos em níveis críticos (Pré-leitor N1, N2) superior à média regional. 
                      <span className="font-bold block mt-2">Requer intervenção imediata para redução de déficit.</span>
                    </p>
                  </div>
                </div>
              ) : (
                <div className="bg-emerald-50 border-l-4 border-emerald-500 p-6 rounded-r-xl h-full shadow-sm flex items-start gap-4">
                   <div className="bg-emerald-100 p-3 rounded-full shrink-0">
                    <ShieldCheck className="w-8 h-8 text-emerald-600" />
                  </div>
                  <div>
                    <h3 className="text-lg font-bold text-emerald-800 mb-2">Situação Estável</h3>
                    <p className="text-emerald-700">
                      Os índices de déficit crítico do município encontram-se abaixo ou iguais à média regional. Mantenha as políticas de alfabetização atuais.
                    </p>
                  </div>
                </div>
              )}
            </div>
          </div>

          {/* Differential Analysis Cards */}
          <section>
            <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wide mb-4">Diferencial de Desempenho</h3>
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
              {/* Combine alerts and highlights into a unified grid for display */}
              {[...analysis.alerts, ...analysis.highlights].map((item, idx) => {
                const isAlert = analysis.alerts.includes(item);
                const isPositiveReduction = !isAlert && (item as any).isReduction; // Green Arrow Down
                const isPositiveGrowth = !isAlert && !(item as any).isReduction; // Green Arrow Up

                // Styling logic
                let borderColor = isAlert ? 'border-red-200' : 'border-emerald-200';
                let bgColor = isAlert ? 'bg-red-50' : 'bg-emerald-50';
                let textColor = isAlert ? 'text-red-800' : 'text-emerald-800';
                let badgeColor = isAlert ? 'text-red-600 bg-red-100' : 'text-emerald-600 bg-emerald-100';

                return (
                  <div key={idx} className={`border ${borderColor} ${bgColor} p-4 rounded-xl flex flex-col justify-between shadow-sm`}>
                    <div className="mb-3">
                      <div className={`font-bold text-sm mb-1 ${textColor}`}>{item.category}</div>
                      <div className={`text-xs opacity-80 ${textColor}`}>
                         {isAlert ? 'Déficit Crítico' : isPositiveReduction ? 'Redução de Déficit' : 'Superavit de Proficiência'}
                      </div>
                    </div>
                    <div className="flex items-end justify-between">
                      <div className={`text-2xl font-bold ${textColor}`}>{item.value.toFixed(1)}%</div>
                      <div className={`flex items-center text-xs font-bold px-2 py-1 rounded-full ${badgeColor}`}>
                        {isPositiveReduction ? (
                           <><ArrowDownRight className="w-3 h-3 mr-1" /> -{item.diff}%</>
                        ) : isAlert ? (
                           <><ArrowUpRight className="w-3 h-3 mr-1" /> +{item.diff}%</>
                        ) : (
                           <><ArrowUpRight className="w-3 h-3 mr-1" /> +{item.diff}%</>
                        )}
                      </div>
                    </div>
                  </div>
                );
              })}
            </div>
          </section>

          {/* Chart Section */}
          <section className="bg-white border border-gray-200 rounded-xl p-6 shadow-sm">
             <div className="mb-6 flex justify-between items-end">
                <div>
                  <h3 className="text-lg font-bold text-gray-900">Curva de Proficiência Comparada</h3>
                  <p className="text-sm text-gray-500">Visualização da distribuição percentual por nível</p>
                </div>
                <div className="flex gap-4 text-xs">
                  <div className="flex items-center gap-2">
                    <span className="w-3 h-3 bg-blue-600 rounded-full"></span>
                    <span className="font-bold text-gray-700">Município</span>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="w-3 h-3 bg-gray-400 rounded-full"></span>
                    <span className="text-gray-500">Regional</span>
                  </div>
                </div>
             </div>

             <div className="h-[350px] w-full">
               <ResponsiveContainer width="100%" height="100%">
                 <LineChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                   <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                   <XAxis 
                      dataKey="name" 
                      tick={{fill: '#6b7280', fontSize: 12}} 
                      axisLine={false}
                      tickLine={false}
                      dy={10}
                   />
                   <YAxis 
                      tick={{fill: '#6b7280', fontSize: 12}} 
                      axisLine={false}
                      tickLine={false}
                      unit="%"
                   />
                   <Tooltip 
