// Helper to calculate IFL for sorting
const calculateIFL = (s: SchoolData) => {
  return ((s.n1 * 0) + (s.n2 * 1) + (s.n3 * 2.5) + (s.n4 * 4) + (s.beginner * 6) + (s.fluent * 10)) / 100;
};

type SortKey = 'name' | 'ifl' | 'participation' | 'fluent' | 'n1n2';

const SchoolPerformance: React.FC = () => {
  const [selectedSchoolId, setSelectedSchoolId] = useState<string>(SCHOOLS_DB[0].name);
  const [sortKey, setSortKey] = useState<SortKey>('ifl');
  const [sortDesc, setSortDesc] = useState(true);

  // Selected School Data
  const selectedSchool = SCHOOLS_DB.find(s => s.name === selectedSchoolId) || SCHOOLS_DB[0];

  // Chart Data Construction
  const chartData = [
    { name: 'Nível 1', Municipal: MUNICIPAL_AVG.n1, Escola: selectedSchool.n1 },
    { name: 'Nível 2', Municipal: MUNICIPAL_AVG.n2, Escola: selectedSchool.n2 },
    { name: 'Nível 3', Municipal: MUNICIPAL_AVG.n3, Escola: selectedSchool.n3 },
    { name: 'Nível 4', Municipal: MUNICIPAL_AVG.n4, Escola: selectedSchool.n4 },
    { name: 'Iniciante', Municipal: MUNICIPAL_AVG.beginner, Escola: selectedSchool.beginner },
    { name: 'Fluente', Municipal: MUNICIPAL_AVG.fluent, Escola: selectedSchool.fluent },
  ];

  // Gap Analysis
  const fluencyDiff = selectedSchool.fluent - MUNICIPAL_AVG.fluent;
  const criticalDiff = (selectedSchool.n1 + selectedSchool.n2) - (MUNICIPAL_AVG.n1 + MUNICIPAL_AVG.n2);

  // Sorting Logic
  const sortedSchools = useMemo(() => {
    const sorted = [...SCHOOLS_DB].sort((a, b) => {
      let valA, valB;
      switch (sortKey) {
        case 'ifl':
          valA = calculateIFL(a);
          valB = calculateIFL(b);
          break;
        case 'participation':
          valA = a.participation;
          valB = b.participation;
          break;
        case 'fluent':
          valA = a.fluent;
          valB = b.fluent;
          break;
        case 'n1n2':
          valA = a.n1 + a.n2;
          valB = b.n1 + b.n2;
          break;
        default:
          valA = a.name;
          valB = b.name;
      }
      return sortDesc ? (valA > valB ? -1 : 1) : (valA > valB ? 1 : -1);
    });
    return sorted;
  }, [sortKey, sortDesc]);

  const handleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortDesc(!sortDesc);
    } else {
      setSortKey(key);
      setSortDesc(true);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* SELECTION AND MAIN CHART */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Controls & School Selector */}
        <div className="lg:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col gap-6">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2 flex items-center gap-2">
              <School className="w-4 h-4" />
              Selecione a Escola
            </label>
            <div className="relative">
              <select
                className="w-full bg-slate-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-3 pr-8 truncate"
                value={selectedSchoolId}
                onChange={(e) => setSelectedSchoolId(e.target.value)}
              >
                {SCHOOLS_DB.map((s) => (
                  <option key={s.name} value={s.name}>
                    {s.name}
                  </option>
                ))}
              </select>
            </div>
          </div>

          {/* GAP ANALYSIS CARDS */}
          <div className="flex flex-col gap-4">
             {/* Positive Highlight */}
             <div className={`p-4 rounded-lg border-l-4 shadow-sm ${fluencyDiff >= 0 ? 'bg-emerald-50 border-emerald-500' : 'bg-gray-50 border-gray-300'}`}>
                <div className="flex items-center justify-between mb-2">
                  <h4 className={`text-sm font-bold ${fluencyDiff >= 0 ? 'text-emerald-800' : 'text-gray-600'}`}>
                    Leitores Fluentes
                  </h4>
                  {fluencyDiff >= 0 ? <TrendingUp className="w-5 h-5 text-emerald-600" /> : <TrendingUp className="w-5 h-5 text-gray-400 rotate-180" />}
                </div>
                <p className="text-xs text-gray-600">
                  {fluencyDiff >= 0 
                    ? `A escola possui ${fluencyDiff.toFixed(1)}% a mais de fluência que a média municipal.` 
                    : `A escola está ${Math.abs(fluencyDiff).toFixed(1)}% abaixo da média municipal em fluência.`}
                </p>
             </div>

             {/* Critical Warning */}
             <div className={`p-4 rounded-lg border-l-4 shadow-sm ${criticalDiff > 0 ? 'bg-red-50 border-red-500' : 'bg-emerald-50 border-emerald-500'}`}>
                <div className="flex items-center justify-between mb-2">
                  <h4 className={`text-sm font-bold ${criticalDiff > 0 ? 'text-red-800' : 'text-emerald-800'}`}>
                    Níveis Críticos (N1+N2)
                  </h4>
                  {criticalDiff > 0 ? <AlertTriangle className="w-5 h-5 text-red-600" /> : <ShieldCheck className="w-5 h-5 text-emerald-600" />}
                </div>
                <p className="text-xs text-gray-600">
                  {criticalDiff > 0 
                    ? `Alerta: Índice de Nível 1 e 2 está ${criticalDiff.toFixed(1)}% superior à média da rede.` 
                    : `Excelente: Índice de Níveis 1 e 2 está ${Math.abs(criticalDiff).toFixed(1)}% inferior à média.`}
                </p>
             </div>
          </div>
        </div>

        {/* COMPARATIVE CHART */}
        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-gray-100">
          <div className="mb-6 flex justify-between items-center">
            <h3 className="text-lg font-bold text-gray-900">Comparativo: Escola vs. Média Municipal</h3>
            <div className="flex items-center gap-4 text-xs">
              <div className="flex items-center gap-1"><div className="w-3 h-3 bg-gray-400 rounded-full"></div> Média Municipal</div>
              <div className="flex items-center gap-1"><div className="w-3 h-3 bg-blue-600 rounded-full"></div> Escola Selecionada</div>
            </div>
          </div>

          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 20, right: 30, left: 0, bottom: 20 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" tick={{fill: '#6b7280', fontSize: 12}} axisLine={false} tickLine={false} dy={10} />
                <YAxis unit="%" tick={{fill: '#6b7280', fontSize: 12}} axisLine={false} tickLine={false} />
                <Tooltip 
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  formatter={(val: number) => [`${val.toFixed(1)}%`, '']}
                />
                {/* Municipal Average Line (Gray, Dashed or Solid thin) */}
                <Line type="monotone" dataKey="Municipal" stroke="#9ca3af" strokeWidth={2} dot={{r: 4, fill: '#9ca3af'}} />
                {/* Selected School Line (Blue/Neon, Thick) */}
                <Line type="monotone" dataKey="Escola" stroke="#2563eb" strokeWidth={3} dot={{r: 6, fill: '#2563eb', stroke: '#fff', strokeWidth: 2}} activeDot={{r: 8}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* DETAILED SCHOOL TABLE */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
          <div>
            <h3 className="text-lg font-bold text-gray-900">Tabela Geral de Escolas</h3>
            <p className="text-sm text-gray-500">Clique nos cabeçalhos para ordenar</p>
          </div>
          <div className="bg-white px-3 py-1 rounded-full border border-gray-200 text-xs font-medium text-gray-500 flex items-center gap-2">
            <Trophy className="w-3 h-3 text-yellow-500" />
            Ordenado por: {sortKey === 'ifl' ? 'IFL (Índice de Fluência)' : sortKey}
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-gray-500 uppercase bg-gray-100">
              <tr>
                <th 
                  className="px-4 py-3 cursor-pointer hover:bg-gray-200" 
                  onClick={() => handleSort('name')}
                >
                  Escola <ArrowUpDown className="w-3 h-3 inline ml-1" />
                </th>
