                  </h4>
                  {criticalDiff > 0 ? <AlertTriangle className="w-5 h-5 text-red-600" /> : <ShieldCheck className="w-5 h-5 text-emerald-600" />}
                </div>
                <p className="text-xs text-gray-600">
                  {criticalDiff > 0 
                    ? `Alerta: Índice de Nível 1 e 2 está ${criticalDiff.toFixed(1)}% superior à média da rede.` 
                    : `Excelente: Índice de Níveis 1 e 2 está ${Math.abs(criticalDiff).toFixed(1)}% inferior à média.`}
                </p>
             </div>
          </div>
