// Helper to calculate IFL for sorting
const calculateIFL = (s: SchoolData) => {
  return ((s.n1 * 0) + (s.n2 * 1) + (s.n3 * 2.5) + (s.n4 * 4) + (s.beginner * 6) + (s.fluent * 10)) / 100;
};

type SortKey = 'name' | 'ifl' | 'participation' | 'fluent' | 'n1n2';

const SchoolPerformance: React.FC = () => {
  const [selectedSchoolId, setSelectedSchoolId] = useState<string>(SCHOOLS_DB[0].name);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortKey, setSortKey] = useState<SortKey>('ifl');
  const [sortDesc, setSortDesc] = useState(true);

  // Filter schools based on search
  const filteredSchools = useMemo(() => {
    return SCHOOLS_DB.filter(school => 
      school.name.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [searchTerm]);

  // Selected School Data
  const selectedSchool = SCHOOLS_DB.find(s => s.name === selectedSchoolId) || SCHOOLS_DB[0];

  // Chart Data Construction
  const chartData = [
    { name: 'Nível 1', Municipal: MUNICIPAL_AVG.n1, Escola: selectedSchool.n1 },
    { name: 'Nível 2', Municipal: MUNICIPAL_AVG.n2, Escola: selectedSchool.n2 },
    { name: 'Nível 3', Municipal: MUNICIPAL_AVG.n3, Escola: selectedSchool.n3 },
    { name: 'Nível 4', Municipal: MUNICIPAL_AVG.n4, Escola: selectedSchool.n4 },
    { name: 'Iniciante', Municipal: MUNICIPAL_AVG.beginner, Escola: selectedSchool.beginner },
    { name: 'Fluente', Municipal: MUNICIPAL_AVG.fluent, Escola: selectedSchool.fluent },
  ];

  // Gap Analysis
  const fluencyDiff = selectedSchool.fluent - MUNICIPAL_AVG.fluent;
  const criticalDiff = (selectedSchool.n1 + selectedSchool.n2) - (MUNICIPAL_AVG.n1 + MUNICIPAL_AVG.n2);

  // Sorting Logic
  const sortedSchools = useMemo(() => {
    const sorted = [...SCHOOLS_DB].sort((a, b) => {
      let valA, valB;
      switch (sortKey) {
        case 'ifl':
          valA = calculateIFL(a);
          valB = calculateIFL(b);
          break;
        case 'participation':
          valA = a.participation;
          valB = b.participation;
          break;
        case 'fluent':
          valA = a.fluent;
          valB = b.fluent;
          break;
        case 'n1n2':
          valA = a.n1 + a.n2;
          valB = b.n1 + b.n2;
          break;
        default:
          valA = a.name;
          valB = b.name;
      }
      return sortDesc ? (valA > valB ? -1 : 1) : (valA > valB ? 1 : -1);
    });
    return sorted;
  }, [sortKey, sortDesc]);

  const handleSort = (key: SortKey) => {
    if (sortKey === key) {
      setSortDesc(!sortDesc);
    } else {
      setSortKey(key);
      setSortDesc(true);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* SELECTION AND MAIN CHART */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Controls & School Selector */}
        <div className="lg:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col gap-6">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2 flex items-center gap-2">
              <School className="w-4 h-4" />
              Selecione a Escola
            </label>

            <div className="space-y-2">
              {/* SEARCH INPUT */}
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Search className="h-4 w-4 text-gray-400" />
                </div>
                <input
                  type="text"
                  className="block w-full pl-10 pr-3 py-2 border border-gray-300 rounded-lg leading-5 bg-white placeholder-gray-500 focus:outline-none focus:placeholder-gray-400 focus:ring-1 focus:ring-blue-500 focus:border-blue-500 sm:text-sm transition duration-150 ease-in-out"
                  placeholder="Buscar nome da escola..."
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                />
              </div>

              {/* DROPDOWN */}
              <div className="relative">
                <select
                  className="w-full bg-slate-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-3 pr-8 text-ellipsis"
                  value={selectedSchoolId}
                  onChange={(e) => setSelectedSchoolId(e.target.value)}
                >
                  {filteredSchools.length > 0 ? (
                    filteredSchools.map((s) => (
                      <option key={s.name} value={s.name}>
                        {s.name}
                      </option>
                    ))
                  ) : (
                    <option disabled>Nenhuma escola encontrada</option>
                  )}
                </select>
                <p className="text-xs text-right text-gray-400 mt-1">
                  {filteredSchools.length} {filteredSchools.length === 1 ? 'escola encontrada' : 'escolas encontradas'}
                </p>
              </div>
            </div>
          </div>

          {/* GAP ANALYSIS CARDS */}
          <div className="flex flex-col gap-4">
             {/* Positive Highlight */}
             <div className={`p-4 rounded-lg border-l-4 shadow-sm ${fluencyDiff >= 0 ? 'bg-emerald-50 border-emerald-500' : 'bg-gray-50 border-gray-300'}`}>
                <div className="flex items-center justify-between mb-2">
                  <h4 className={`text-sm font-bold ${fluencyDiff >= 0 ? 'text-emerald-800' : 'text-gray-600'}`}>
                    Leitores Fluentes
                  </h4>
                  {fluencyDiff >= 0 ? <TrendingUp className="w-5 h-5 text-emerald-600" /> : <TrendingUp className="w-5 h-5 text-gray-400 rotate-180" />}
                </div>
                <p className="text-xs text-gray-600">
                  {fluencyDiff >= 0 
                    ? `A escola possui ${fluencyDiff.toFixed(1)}% a mais de fluência que a média municipal.` 
                    : `A escola está ${Math.abs(fluencyDiff).toFixed(1)}% abaixo da média municipal em fluência.`}
                </p>
             </div>

             {/* Critical Warning */}
             <div className={`p-4 rounded-lg border-l-4 shadow-sm ${criticalDiff > 0 ? 'bg-red-50 border-red-500' : 'bg-emerald-50 border-emerald-500'}`}>
                <div className="flex items-center justify-between mb-2">
                  <h4 className={`text-sm font-bold ${criticalDiff > 0 ? 'text-red-800' : 'text-emerald-800'}`}>
                    Níveis Críticos (N1+N2)
                  </h4>
                  {criticalDiff > 0 ? <AlertTriangle className="w-5 h-5 text-red-600" /> : <ShieldCheck className="w-5 h-5 text-emerald-600" />}
                </div>
                <p className="text-xs text-gray-600">
