                <th className="px-4 py-3 text-center bg-cyan-50">Pré-leitor (Total)</th>
                <th 
                  className="px-4 py-3 text-center bg-red-50 cursor-pointer hover:bg-red-100"
                  onClick={() => handleSort('n1n2')}
                >
                  Nível 1+2 <ArrowUpDown className="w-3 h-3 inline ml-1" />
                </th>
                <th className="px-4 py-3 text-center">Nível 3</th>
                <th className="px-4 py-3 text-center">Nível 4</th>
