                    <td className="px-4 py-3 text-center text-gray-600">{s.evaluated}</td>
                    <td className="px-4 py-3 text-center font-semibold text-gray-800">
                      {s.participation}%
                    </td>
                    <td className="px-4 py-3 text-center text-cyan-700 bg-cyan-50/30">{s.preReaderTotal.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center font-bold text-red-600 bg-red-50/30">
                      {(s.n1 + s.n2).toFixed(1)}%
                    </td>
                    <td className="px-4 py-3 text-center text-gray-500">{s.n3.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-gray-500">{s.n4.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-blue-700 bg-blue-50/30 font-medium">{s.beginner.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-indigo-700 bg-indigo-50/30 font-bold">{s.fluent.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-purple-700 bg-purple-50/30 font-extrabold">{ifl.toFixed(2)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

