                    <td className="px-4 py-3 text-center text-gray-500">{s.n4.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-blue-700 bg-blue-50/30 font-medium">{s.beginner.toFixed(1)}%</td>
