                    <td className="px-4 py-3 text-center text-purple-700 bg-purple-50/30 font-extrabold">{ifl.toFixed(2)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

