import React, { useMemo, useState } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, ReferenceLine, Cell
} from 'recharts';
import { Map, AlertOctagon, CheckCircle2, Scale, Trophy, Users } from 'lucide-react';
import { SCHOOLS_DB, calculateIFL } from './SchoolPerformance';
import { SchoolData } from '../types';

// MAPPING LOGIC: Map Sector to Partial Names in DB
const SECTOR_MAPPING: Record<string, string[]> = {
  "SETOR 1": ["ANDRE FRANCO MONTORO", "ARANTES VASQUES", "DULCE PEDROSA", "GILDA PIORINI", "MARIA ZARA", "MOACYR DE ALMEIDA", "PAULO FREIRE"],
  "SETOR 4": ["MARIA APARECIDA CAMARGO", "AUGUSTO CESAR", "DONA MINICA", "FELIX ADIB", "MARIO ANTONIO BONOTTI", "ORLANDO PIRES"],
  "SETOR 5": ["ANGELO PAZ", "ELIAS BARGIS", "JOAO KOLENDA", "MADALENA", "REGINA CELIA", "VITO ARDITO"],
  "SETOR 7": ["ALEXANDRE MACHADO", "ARTHUR DE ANDRADE", "JOAO CESARIO", "MARIA HELENA", "RUTH AZEVEDO", "YVONE"],
  "SETOR 9": ["FRANCISCO DE ASSIS", "JOAQUIM PEREIRA", "LAURO VICENTE", "MARIO DE ASSIS", "RACHEL DE AGUIAR", "SEU JUQUINHA"],
  "SETOR 10": ["ABDIAS", "ISABEL DO CARMO", "JULIETA REALE", "ODETE", "PADRE ZEZINHO", "SERAFIM"]
};

const SECTOR_COLORS: Record<string, string> = {
  "SETOR 1": "#3b82f6", // Blue
  "SETOR 4": "#8b5cf6", // Violet
  "SETOR 5": "#ec4899", // Pink
  "SETOR 7": "#f59e0b", // Amber
  "SETOR 9": "#10b981", // Emerald
  "SETOR 10": "#6366f1" // Indigo
};

const SectorAnalysis: React.FC = () => {
  const [selectedSector, setSelectedSector] = useState("SETOR 1");

  // Filter schools for the selected sector
  const sectorSchools = useMemo(() => {
    const searchTerms = SECTOR_MAPPING[selectedSector] || [];
    return SCHOOLS_DB.filter(school => {
      // Robust partial match
      return searchTerms.some(term => school.name.toUpperCase().includes(term));
    });
  }, [selectedSector]);

  // Calculate Aggregates for the Sector
  const aggregates = useMemo(() => {
    const totalSchools = sectorSchools.length;
    if (totalSchools === 0) return null;

    // Simple Average of IFLs (Standard for dashboards showing school performance comparison)
    const avgIFL = sectorSchools.reduce((acc, s) => acc + calculateIFL(s), 0) / totalSchools;

    // Weighted Average for Percentages based on 'evaluated' count gives a more accurate population view
    const totalEvaluated = sectorSchools.reduce((acc, s) => acc + s.evaluated, 0);

    const criticalDeficit = sectorSchools.reduce((acc, s) => acc + ((s.n1 + s.n2) * s.evaluated), 0) / totalEvaluated;
    const excellenceIndex = sectorSchools.reduce((acc, s) => acc + (s.fluent * s.evaluated), 0) / totalEvaluated;

    // Equity Amplitude
    const ifls = sectorSchools.map(calculateIFL);
    const maxIFL = Math.max(...ifls);
    const minIFL = Math.min(...ifls);
    const amplitude = maxIFL - minIFL;
    const bestSchool = sectorSchools.find(s => calculateIFL(s) === maxIFL)?.name;
    const challengeSchool = sectorSchools.find(s => calculateIFL(s) === minIFL)?.name;

    return {
      avgIFL,
      criticalDeficit,
      excellenceIndex,
      amplitude,
      bestSchool,
      challengeSchool,
      totalEvaluated
    };
  }, [sectorSchools]);

  // Chart Data Preparation
  const chartData = useMemo(() => {
    return sectorSchools.map(s => ({
      name: s.name.length > 25 ? s.name.substring(0, 22) + '...' : s.name, // Truncate for X-Axis
      fullName: s.name,
      ifl: calculateIFL(s).toFixed(2),
      rawIFL: calculateIFL(s)
    })).sort((a, b) => b.rawIFL - a.rawIFL); // Sort by performance descending
  }, [sectorSchools]);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">

      {/* SECTOR SELECTOR */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-slate-100 p-3 rounded-full">
                <Map className="w-6 h-6 text-slate-700" />
             </div>
             <div>
                <h2 className="text-xl font-bold text-gray-900">Análise Estratégica por Setores</h2>
                <p className="text-sm text-gray-500">Agrupamento regional para gestão educacional focada</p>
             </div>
          </div>

          <div className="flex flex-wrap gap-2 justify-center md:justify-end">
            {Object.keys(SECTOR_MAPPING).map(sector => (
              <button
                key={sector}
                onClick={() => setSelectedSector(sector)}
                className={`px-4 py-2 text-sm font-medium rounded-lg transition-all ${
                  selectedSector === sector 
                    ? 'bg-slate-800 text-white shadow-md transform scale-105' 
                    : 'bg-white border border-gray-200 text-gray-600 hover:bg-gray-50'
                }`}
              >
                {sector}
              </button>
            ))}
          </div>
        </div>
      </div>

      {aggregates && (
        <>
          {/* KPI CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* IFL MEDIO */}
            <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm flex flex-col justify-between relative overflow-hidden">
              <div className="absolute top-0 right-0 w-20 h-20 bg-blue-50 rounded-bl-full -mr-4 -mt-4 z-0"></div>
              <div className="relative z-10">
                <div className="flex items-center gap-2 mb-2 text-gray-500 text-sm font-semibold uppercase tracking-wider">
                  <Trophy className="w-4 h-4" /> IFL Médio do Setor
                </div>
                <div className="text-4xl font-extrabold text-gray-900">{aggregates.avgIFL.toFixed(2)}</div>
                <p className="text-xs text-gray-400 mt-2">Média ponderada (Escala 0-10)</p>
              </div>
            </div>

            {/* DEFICIT CRITICO */}
            <div className={`p-6 rounded-xl border shadow-sm flex flex-col justify-between ${aggregates.criticalDeficit > 20 ? 'bg-red-50 border-red-200' : 'bg-white border-gray-100'}`}>
              <div>
                <div className={`flex items-center gap-2 mb-2 text-sm font-semibold uppercase tracking-wider ${aggregates.criticalDeficit > 20 ? 'text-red-700' : 'text-gray-500'}`}>
                  <AlertOctagon className="w-4 h-4" /> Índice de Déficit Crítico
                </div>
                <div className={`text-4xl font-extrabold ${aggregates.criticalDeficit > 20 ? 'text-red-600' : 'text-gray-900'}`}>
                  {aggregates.criticalDeficit.toFixed(1)}%
                </div>
                <p className={`text-xs mt-2 ${aggregates.criticalDeficit > 20 ? 'text-red-500 font-bold' : 'text-gray-400'}`}>
                  {aggregates.criticalDeficit > 20 ? 'Alerta: Acima do limite de 20%' : 'Nível Aceitável (N1 + N2)'}
                </p>
              </div>
            </div>

            {/* EXCELENCIA REGIONAL */}
            <div className={`p-6 rounded-xl border shadow-sm flex flex-col justify-between ${aggregates.excellenceIndex > 50 ? 'bg-emerald-50 border-emerald-200' : 'bg-white border-gray-100'}`}>
              <div>
                <div className={`flex items-center gap-2 mb-2 text-sm font-semibold uppercase tracking-wider ${aggregates.excellenceIndex > 50 ? 'text-emerald-700' : 'text-gray-500'}`}>
                  <CheckCircle2 className="w-4 h-4" /> Excelência Regional
                </div>
                <div className={`text-4xl font-extrabold ${aggregates.excellenceIndex > 50 ? 'text-emerald-600' : 'text-gray-900'}`}>
                  {aggregates.excellenceIndex.toFixed(1)}%
                </div>
                <p className={`text-xs mt-2 ${aggregates.excellenceIndex > 50 ? 'text-emerald-600 font-bold' : 'text-gray-400'}`}>
                  {aggregates.excellenceIndex > 50 ? 'Meta de 50% Atingida!' : 'Percentual de Fluentes'}
                </p>
              </div>
            </div>

            {/* AMPLITUDE DE EQUIDADE */}
            <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm flex flex-col justify-between">
               <div>
                <div className="flex items-center gap-2 mb-2 text-gray-500 text-sm font-semibold uppercase tracking-wider">
                  <Scale className="w-4 h-4" /> Amplitude de Equidade
                </div>
                <div className="text-4xl font-extrabold text-indigo-600">{aggregates.amplitude.toFixed(2)}</div>
                <p className="text-xs text-gray-400 mt-2">Diferença (Máx - Mín IFL)</p>
              </div>
              <div className="w-full bg-gray-100 h-1.5 mt-3 rounded-full overflow-hidden">
                {/* Visual bar showing disparity severity. Assuming max disparity ~5.0 */}
                <div 
                  className={`h-full ${aggregates.amplitude > 3 ? 'bg-red-400' : 'bg-indigo-400'}`} 
                  style={{ width: `${Math.min((aggregates.amplitude / 5) * 100, 100)}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* MAIN CHART SECTION */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

            {/* BAR CHART */}
            <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
              <div className="flex justify-between items-center mb-6">
                <div>
                   <h3 className="text-lg font-bold text-gray-900">Comparativo Intra-Setor</h3>
                   <p className="text-sm text-gray-500">Desempenho IFL por unidade escolar</p>
                </div>
                <div className="flex items-center gap-2 text-xs font-medium bg-slate-100 px-3 py-1 rounded-full text-slate-600">
                  <div className="w-3 h-3 border-t-2 border-red-500 border-dashed"></div> Média do Setor: {aggregates.avgIFL.toFixed(2)}
                </div>
              </div>

              <div className="h-[400px] w-full">
                <ResponsiveContainer width="100%" height="100%">
                  <BarChart
                    data={chartData}
                    margin={{ top: 20, right: 30, left: 20, bottom: 60 }}
                  >
                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                    <XAxis 
                      dataKey="name" 
                      interval={0} 
                      angle={-45} 
                      textAnchor="end" 
                      height={80} 
                      tick={{fontSize: 10, fill: '#64748b'}} 
                    />
                    <YAxis 
                      domain={[0, 10]} 
                      tick={{fontSize: 12, fill: '#64748b'}} 
                    />
                    <Tooltip 
                      cursor={{fill: '#f8fafc'}}
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                      formatter={(val: string) => [val, 'IFL']}
                      labelFormatter={(label) => chartData.find(c => c.name === label)?.fullName || label}
                    />
                    <ReferenceLine y={aggregates.avgIFL} stroke="#ef4444" strokeDasharray="3 3" label={{ position: 'right', value: 'Média', fill: '#ef4444', fontSize: 10 }} />
                    <Bar dataKey="ifl" radius={[4, 4, 0, 0]}>
                      {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={SECTOR_COLORS[selectedSector] || '#3b82f6'} />
                      ))}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* SIDEBAR DETAILS */}
            <div className="bg-slate-50 p-6 rounded-xl border border-slate-100 flex flex-col gap-6">

              <div>
                <h4 className="font-bold text-gray-900 mb-4 flex items-center gap-2">
                  <Users className="w-4 h-4 text-slate-500" />
                  Escolas no Grupo
                </h4>
                <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar">
                  {chartData.map((s, idx) => (
                    <div key={idx} className="bg-white p-3 rounded-lg border border-gray-200 shadow-sm text-xs">
                      <div className="font-bold text-gray-800 mb-1">{s.fullName}</div>
                      <div className="flex justify-between items-center">
                        <span className="text-gray-500">IFL:</span>
                        <span className={`font-bold px-2 py-0.5 rounded ${parseFloat(s.ifl) >= aggregates.avgIFL ? 'bg-green-100 text-green-700' : 'bg-red-50 text-red-700'}`}>
