};

// Helper to calculate classification based on IFL score
const getIFLClassification = (score: number) => {
  if (score > 8.0) return { label: 'Excelente', color: 'bg-emerald-100 text-emerald-800 border-emerald-200' };
  if (score > 6.0) return { label: 'Bom', color: 'bg-blue-100 text-blue-800 border-blue-200' };
  return { label: 'Atenção', color: 'bg-amber-100 text-amber-800 border-amber-200' };
};

// Helper to clean school names for chart display
const cleanSchoolName = (name: string) => {
  return name
    .replace(/ESCOLA MUNICIPAL\s+/g, '')
    .replace(/ESCOLA MUN\s+/g, '')
    .replace(/EM PROFA\s+/g, '')
    .replace(/EM PROF\s+/g, '')
    .replace(/PROFESSORA\s+/g, '')
    .replace(/PROFESSOR\s+/g, '')
    .replace(/PROFA\s+/g, '')
    .replace(/PROF\s+/g, '')
    .replace(/DOUTOR\s+/g, '')
    .replace(/DR\s+/g, '')
    .trim();
};

// Custom Tick Component for Text Wrapping on XAxis
const CustomizedAxisTick = (props: any) => {
  const { x, y, payload } = props;
  const words = payload.value.split(' ');

  return (
    <g transform={`translate(${x},${y})`}>
      <text x={0} y={0} dy={10} textAnchor="middle" fill="#64748b" fontSize={9} fontWeight={600}>
        {words.map((word: string, index: number) => (
          <tspan x="0" dy="1.1em" key={index}>
            {word}
          </tspan>
        ))}
      </text>
    </g>
  );
};

const SectorAnalysis: React.FC = () => {
  const [selectedSector, setSelectedSector] = useState("SETOR 1");

  // 1. Calculate stats for ALL sectors to identify the lowest performing one globally
  const globalSectorStats = useMemo(() => {
    return Object.keys(SECTOR_MAPPING).map(sectorName => {
      const searchTerms = SECTOR_MAPPING[sectorName] || [];
      const schools = SCHOOLS_DB.filter(school => 
        searchTerms.some(term => school.name.toUpperCase().includes(term))
      );

      const avgIFL = schools.length > 0 
        ? schools.reduce((acc, s) => acc + calculateIFL(s), 0) / schools.length 
        : 0;

      return { sectorName, avgIFL };
    });
  }, []);

  const lowestSector = useMemo(() => {
    return [...globalSectorStats].sort((a, b) => a.avgIFL - b.avgIFL)[0];
  }, [globalSectorStats]);

  // 2. Filter schools for the CURRENTLY selected sector
  const sectorSchools = useMemo(() => {
    const searchTerms = SECTOR_MAPPING[selectedSector] || [];
    return SCHOOLS_DB.filter(school => {
      return searchTerms.some(term => school.name.toUpperCase().includes(term));
    });
  }, [selectedSector]);

  // 3. Calculate Aggregates for the Selected Sector
  const aggregates = useMemo(() => {
    const totalSchools = sectorSchools.length;
    if (totalSchools === 0) return null;

    // Simple Average of IFLs
    const avgIFL = sectorSchools.reduce((acc, s) => acc + calculateIFL(s), 0) / totalSchools;

    // Weighted Average for Percentages
    const totalEvaluated = sectorSchools.reduce((acc, s) => acc + s.evaluated, 0);

    // Critical Deficit (N1 + N2)
    const criticalDeficit = sectorSchools.reduce((acc, s) => acc + ((s.n1 + s.n2) * s.evaluated), 0) / totalEvaluated;

    // Excellence Index (Beginner + Fluent)
    const excellenceIndex = sectorSchools.reduce((acc, s) => acc + ((s.beginner + s.fluent) * s.evaluated), 0) / totalEvaluated;

    // Equity Amplitude
    const ifls = sectorSchools.map(calculateIFL);
    const maxIFL = Math.max(...ifls);
    const minIFL = Math.min(...ifls);
    const amplitude = maxIFL - minIFL;
    const bestSchool = sectorSchools.find(s => calculateIFL(s) === maxIFL)?.name;
    const challengeSchool = sectorSchools.find(s => calculateIFL(s) === minIFL)?.name;

    return {
      avgIFL,
      criticalDeficit,
      excellenceIndex,
      amplitude,
      bestSchool,
      challengeSchool,
      totalEvaluated
    };
  }, [sectorSchools]);

  // 4. Chart Data Preparation
  const chartData = useMemo(() => {
    return sectorSchools.map(s => ({
      name: cleanSchoolName(s.name), // Simplified Name for Axis
      fullName: s.name, // Full name for Tooltip
      ifl: parseFloat(calculateIFL(s).toFixed(2)),
      rawIFL: calculateIFL(s)
    })).sort((a, b) => b.rawIFL - a.rawIFL); 
  }, [sectorSchools]);

  const classification = aggregates ? getIFLClassification(aggregates.avgIFL) : { label: '-', color: '' };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">

      {/* EMERGENCY ALERT BANNER */}
      {selectedSector === lowestSector.sectorName && (
        <div className="bg-red-600 rounded-xl shadow-lg p-4 flex items-center justify-between text-white animate-pulse">
          <div className="flex items-center gap-3">
             <div className="bg-white/20 p-2 rounded-full">
               <AlertTriangle className="w-6 h-6 text-white" />
             </div>
             <div>
               <h3 className="font-bold text-lg">⚠️ ATENÇÃO: Setor Prioritário</h3>
               <p className="text-sm text-white/90">
                 Atenção: O {selectedSector} apresenta o menor desempenho médio de fluência da rede.
               </p>
             </div>
          </div>
          <button className="bg-white text-red-700 px-4 py-2 rounded-lg text-sm font-bold hover:bg-red-50 transition-colors">
            Ver Plano de Ação
          </button>
        </div>
      )}

      {/* SECTOR SELECTOR */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
        <div className="flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
             <div className="bg-slate-100 p-3 rounded-full">
                <Map className="w-6 h-6 text-slate-700" />
             </div>
             <div>
                <h2 className="text-xl font-bold text-gray-900">Análise Estratégica por Setores</h2>
                <p className="text-sm text-gray-500">Agrupamento regional para gestão educacional focada</p>
             </div>
          </div>

          <div className="flex flex-wrap gap-2 justify-center md:justify-end">
            {Object.keys(SECTOR_MAPPING).map(sector => (
              <button
                key={sector}
                onClick={() => setSelectedSector(sector)}
                className={`px-4 py-2 text-sm font-medium rounded-lg transition-all ${
                  selectedSector === sector 
                    ? 'bg-slate-800 text-white shadow-md transform scale-105' 
                    : 'bg-white border border-gray-200 text-gray-600 hover:bg-gray-50'
                }`}
              >
                {sector}
              </button>
            ))}
          </div>
        </div>
      </div>

      {aggregates && (
        <>
          {/* KPI CARDS */}
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

            {/* IFL MEDIO */}
            <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm flex flex-col justify-between relative overflow-hidden">
              <div className="absolute top-0 right-0 w-20 h-20 bg-blue-50 rounded-bl-full -mr-4 -mt-4 z-0"></div>
              <div className="relative z-10">
                <div className="flex items-center justify-between mb-2">
                   <div className="flex items-center gap-2 text-gray-500 text-sm font-semibold uppercase tracking-wider">
                     <Trophy className="w-4 h-4" /> IFL Médio
                   </div>
                   <span className={`text-xs font-bold px-2 py-1 rounded border ${classification.color}`}>
                     {classification.label}
                   </span>
                </div>
                <div className="text-4xl font-extrabold text-gray-900">{aggregates.avgIFL.toFixed(2)}</div>
                <p className="text-xs text-gray-400 mt-2">Média ponderada (Escala 0-10)</p>
              </div>
            </div>

            {/* INDICE DE ALERTA CRITICO (N1+N2) - UPDATED TO NEW SPECS */}
            <div className={`p-6 rounded-xl border shadow-sm flex flex-col justify-between ${aggregates.criticalDeficit > 15 ? 'bg-red-600 border-red-700 text-white' : 'bg-blue-900 border-blue-800 text-white'}`}>
              <div>
                <div className={`flex items-center gap-2 mb-2 text-sm font-semibold uppercase tracking-wider ${aggregates.criticalDeficit > 15 ? 'text-red-100' : 'text-blue-200'}`}>
                  <AlertOctagon className="w-4 h-4" /> Índice de Alerta Crítico
                </div>
                <div className="text-4xl font-extrabold text-white">
                  {aggregates.criticalDeficit.toFixed(1)}%
                </div>
                <p className={`text-xs mt-2 font-bold ${aggregates.criticalDeficit > 15 ? 'text-red-100' : 'text-blue-200'}`}>
                  {aggregates.criticalDeficit > 15 ? 'ALERTA: INTERVENÇÃO URGENTE' : 'Nível de Atenção Controlado'}
                </p>
              </div>
            </div>

            {/* EXCELENCIA REGIONAL - GREEN IF >= 70% */}
            <div className={`p-6 rounded-xl border shadow-sm flex flex-col justify-between ${aggregates.excellenceIndex >= 70 ? 'bg-emerald-50 border-emerald-200' : 'bg-amber-50 border-amber-200'}`}>
              <div>
                <div className={`flex items-center gap-2 mb-2 text-sm font-semibold uppercase tracking-wider ${aggregates.excellenceIndex >= 70 ? 'text-emerald-700' : 'text-amber-700'}`}>
                  <CheckCircle2 className="w-4 h-4" /> Excelência (Inic+Flu)
                </div>
                <div className={`text-4xl font-extrabold ${aggregates.excellenceIndex >= 70 ? 'text-emerald-600' : 'text-amber-600'}`}>
                  {aggregates.excellenceIndex.toFixed(1)}%
                </div>
                <p className={`text-xs mt-2 font-bold ${aggregates.excellenceIndex >= 70 ? 'text-emerald-600' : 'text-amber-600'}`}>
                  {aggregates.excellenceIndex >= 70 ? 'Meta de 70% Atingida!' : 'Em desenvolvimento (< 70%)'}
                </p>
              </div>
            </div>

            {/* AMPLITUDE DE EQUIDADE */}
            <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm flex flex-col justify-between">
               <div>
                <div className="flex items-center gap-2 mb-2 text-gray-500 text-sm font-semibold uppercase tracking-wider">
                  <Scale className="w-4 h-4" /> Amplitude de Equidade
