                  style={{ width: `${Math.min((aggregates.amplitude / 5) * 100, 100)}%` }}
                ></div>
              </div>
            </div>
          </div>

          {/* MAIN CHART SECTION */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

            {/* BAR CHART */}
            <div className="lg:col-span-2 bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
