// Helper to calculate IFL for sorting
export const calculateIFL = (s: SchoolData) => {
  return ((s.n1 * 0) + (s.n2 * 1) + (s.n3 * 2.5) + (s.n4 * 4) + (s.beginner * 6) + (s.fluent * 10)) / 100;
};

// Helper to find sector
const getSchoolSector = (schoolName: string) => {
  for (const [sector, schools] of Object.entries(SECTOR_MAPPING_REF)) {
    if (schools.some(s => schoolName.toUpperCase().includes(s))) {
      return sector;
    }
  }
  return "NÃO IDENTIFICADO";
};

// Helper to calculate Sector Averages
const calculateSectorAverage = (sectorName: string) => {
  const searchTerms = SECTOR_MAPPING_REF[sectorName] || [];
  const schools = SCHOOLS_DB.filter(school => 
    searchTerms.some(term => school.name.toUpperCase().includes(term))
  );

  if (schools.length === 0) return 0;

  const totalIFL = schools.reduce((acc, s) => acc + calculateIFL(s), 0);
  return totalIFL / schools.length;
};

type SortKey = 'name' | 'ifl' | 'participation' | 'fluent' | 'n1n2';

