        doc.setFillColor(255, 255, 255);
        doc.roundedRect(x, startY, 55, 30, 2, 2, 'FD');

        doc.setFontSize(9);
        doc.setTextColor(100, 100, 100);
        doc.setFont("helvetica", "normal");
        doc.text(title, x + 27.5, startY + 10, { align: 'center' });

        doc.setFontSize(20);
        doc.setTextColor(valueColor[0], valueColor[1], valueColor[2]);
        doc.setFont("helvetica", "bold");
        doc.text(value, x + 27.5, startY + 24, { align: 'center' });
    };

    drawCard(15, "IFL Escola", schoolIFL.toFixed(2), primaryColor);
    drawCard(77.5, "Média do Setor", sectorAvg.toFixed(2), darkColor);
    drawCard(140, "Média Municipal", municipalIFL.toFixed(2), darkColor);

    // --- ALERT ANALYSIS ---
    const criticalSum = selectedSchool.n1 + selectedSchool.n2;
    const isAlert = criticalSum > 15;

    const alertBoxY = 110;
    const alertBoxH = 25; // Fixed height

    doc.setDrawColor(isAlert ? dangerColor[0] : successColor[0], isAlert ? dangerColor[1] : successColor[1], isAlert ? dangerColor[2] : successColor[2]);
    doc.setFillColor(isAlert ? 254 : 240, isAlert ? 242 : 253, isAlert ? 242 : 244);
    doc.roundedRect(15, alertBoxY, 180, alertBoxH, 2, 2, 'FD');

    // Status Title
    doc.setTextColor(isAlert ? 185 : 6, isAlert ? 28 : 120, isAlert ? 28 : 100); // Darker red or green
    doc.setFontSize(11);
    doc.setFont("helvetica", "bold");
    const alertTitle = isAlert ? "ALERTA CRÍTICO" : "SITUAÇÃO CONTROLADA";
    doc.text(alertTitle, 22, alertBoxY + 16);

    // Status Description (Wrapped)
    doc.setFont("helvetica", "normal");
    doc.setTextColor(50, 50, 50);
    doc.setFontSize(10);

    const alertText = isAlert 
        ? `Atenção: A escola apresenta ${criticalSum.toFixed(1)}% de alunos nos níveis N1+N2. Requer plano de intervenção pedagógica imediata.`
        : `Índices de N1+N2 (${criticalSum.toFixed(1)}%) dentro da meta de segurança estabelecida pela rede (<15%).`;

    // Wrap text within approx 100 units width (from x=90 to x=190)
    const splitAlertText = doc.splitTextToSize(alertText, 100);
    doc.text(splitAlertText, 90, alertBoxY + 9); // Adjust Y to center loosely

    // --- VECTOR LINE CHART ---
    const chartY = 155;
    const chartH = 80;
    const chartW = 160;
    const chartX = 25;

    doc.setTextColor(30, 30, 30);
    doc.setFontSize(12);
    doc.setFont("helvetica", "bold");
    doc.text("Comparativo de Proficiência por Nível", 15, 148);

    // Axis
    doc.setDrawColor(200);
    doc.setLineWidth(0.5);
    doc.line(chartX, chartY, chartX, chartY + chartH); // Y Axis
    doc.line(chartX, chartY + chartH, chartX + chartW, chartY + chartH); // X Axis

    // Grid lines
    doc.setLineWidth(0.1);
    doc.setDrawColor(220);
    for(let i = 0; i <= 5; i++) {
        const yPos = chartY + (chartH * (i/5));
        doc.line(chartX, yPos, chartX + chartW, yPos);
        doc.setFontSize(8);
        doc.setTextColor(150);
        doc.text(`${100 - (i*20)}%`, chartX - 2, yPos + 3, { align: 'right' });
    }

    // Data Plotting
    const labels = ['N1', 'N2', 'N3', 'N4', 'Inic.', 'Fluente'];
    const schoolValues = [selectedSchool.n1, selectedSchool.n2, selectedSchool.n3, selectedSchool.n4, selectedSchool.beginner, selectedSchool.fluent];
    const muniValues = [MUNICIPAL_AVG.n1, MUNICIPAL_AVG.n2, MUNICIPAL_AVG.n3, MUNICIPAL_AVG.n4, MUNICIPAL_AVG.beginner, MUNICIPAL_AVG.fluent];
    const stepX = chartW / (labels.length - 1);

    // Plot Municipal (Gray Line)
    doc.setDrawColor(160, 160, 160);
    doc.setLineWidth(1.5);
    let pathMuni = [];
    for (let i = 0; i < muniValues.length; i++) {
        const x = chartX + (i * stepX);
        const y = chartY + chartH - ((muniValues[i] / 100) * chartH);
        pathMuni.push({x, y});
        if (i > 0) doc.line(pathMuni[i-1].x, pathMuni[i-1].y, x, y);
    }
    // Dots Municipal
    doc.setFillColor(160, 160, 160);
    pathMuni.forEach(p => doc.circle(p.x, p.y, 1.5, 'F'));

    // Plot School (Blue Line)
    doc.setDrawColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.setLineWidth(2.5);
    let pathSchool = [];
    for (let i = 0; i < schoolValues.length; i++) {
        const x = chartX + (i * stepX);
        const y = chartY + chartH - ((schoolValues[i] / 100) * chartH);
        pathSchool.push({x, y});
        if (i > 0) doc.line(pathSchool[i-1].x, pathSchool[i-1].y, x, y);
    }
    // Dots School
    doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.setDrawColor(255, 255, 255);
    doc.setLineWidth(1); // border for dot
    pathSchool.forEach(p => {
        doc.circle(p.x, p.y, 2.5, 'FD');
    });

    // Labels X Axis
    doc.setTextColor(80, 80, 80);
    doc.setFontSize(9);
    doc.setFont("helvetica", "normal");
    labels.forEach((label, i) => {
        doc.text(label, chartX + (i * stepX), chartY + chartH + 8, { align: 'center' });
    });

    // Legend
    const legendY = chartY + chartH + 20;
    // Muni
    doc.setFillColor(160, 160, 160);
    doc.circle(chartX + 30, legendY, 2, 'F');
    doc.text("Média Municipal", chartX + 35, legendY + 1);
    // School
    doc.setFillColor(primaryColor[0], primaryColor[1], primaryColor[2]);
    doc.circle(chartX + 90, legendY, 2, 'F');
    doc.text("Escola Selecionada", chartX + 95, legendY + 1);

    // --- FOOTER ---
    const pageHeight = doc.internal.pageSize.height;
    const footerY = pageHeight - 15;

    doc.setDrawColor(200);
    doc.line(15, footerY - 5, 195, footerY - 5);

    // Left: System Info
    doc.setFontSize(8);
    doc.setTextColor(150);
    doc.text("Documento gerado digitalmente via PIPA Voice AI", 15, footerY + 5);
    doc.text("A autenticidade destes dados depende da base oficial.", 15, footerY + 9);

    // Right: Signature/Logo
    doc.setFontSize(12);
    doc.setFont("helvetica", "bold");
    doc.setTextColor(50);
    doc.text("HCC", 195, footerY + 2, { align: 'right' }); // Text Logo

    doc.setFontSize(7);
    doc.setFont("helvetica", "normal");
    doc.setTextColor(150);
    doc.text("Desenvolvido por HCC © 2026", 195, footerY + 8, { align: 'right' });

    // Save
    const safeName = selectedSchool.name.substring(0, 30).replace(/[^a-z0-9]/gi, '_');
    doc.save(`Relatorio_PIPA_${safeName}.pdf`);
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      {/* SELECTION AND MAIN CHART */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Controls & School Selector */}
        <div className="lg:col-span-1 bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col gap-6">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-2 flex items-center gap-2">
              <School className="w-4 h-4" />
              Selecione a Escola
            </label>

            <div className="space-y-2">
              {/* SEARCH INPUT */}
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                  <Search className="h-4 w-4 text-gray-400" />
                </div>
                <input
                  type="text"
                  className={`block w-full pl-10 pr-8 py-2 border rounded-lg leading-5 bg-white placeholder-gray-500 focus:outline-none focus:placeholder-gray-400 focus:ring-1 sm:text-sm transition duration-150 ease-in-out ${
                    searchTerm && filteredSchools.length === 0 
                      ? 'border-red-300 focus:border-red-500 focus:ring-red-500' 
                      : 'border-gray-300 focus:border-blue-500 focus:ring-blue-500'
                  }`}
                  placeholder="Buscar nome da escola (Tecle Enter)"
                  value={searchTerm}
                  onChange={(e) => setSearchTerm(e.target.value)}
                  onKeyDown={handleKeyDown}
                />
                {searchTerm && (
                  <button 
                    onClick={() => setSearchTerm('')}
                    className="absolute inset-y-0 right-0 pr-3 flex items-center text-gray-400 hover:text-gray-600"
                  >
                    <X className="h-4 w-4" />
                  </button>
                )}
              </div>

              {/* ERROR MESSAGE */}
              {searchTerm && filteredSchools.length === 0 && (
                <div className="flex items-center gap-1.5 text-xs text-red-600 animate-in fade-in slide-in-from-top-1">
                  <AlertTriangle className="w-3 h-3" />
                  <span>Escola não encontrada na rede.</span>
                </div>
              )}

              {/* DROPDOWN */}
              <div className="relative">
                <select
                  className="w-full bg-slate-50 border border-gray-300 text-gray-900 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-3 pr-8 text-ellipsis"
                  value={selectedSchoolId}
                  onChange={(e) => handleSelectSchool(e.target.value)}
                >
                  {filteredSchools.length > 0 ? (
                    filteredSchools.map((s) => (
                      <option key={s.name} value={s.name}>
                        {s.name}
                      </option>
                    ))
                  ) : (
                    <option disabled>Nenhuma escola encontrada</option>
                  )}
                </select>
                <p className="text-xs text-right text-gray-400 mt-1">
                  {filteredSchools.length} {filteredSchools.length === 1 ? 'escola encontrada' : 'escolas encontradas'}
                </p>
              </div>
            </div>
          </div>

          {/* EXPORT BUTTON */}
          <button
            onClick={generateIndividualPDF}
            className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2.5 rounded-lg text-sm font-semibold transition-colors shadow-sm"
          >
            <FileText className="w-4 h-4" />
            Gerar Relatório Pedagógico Individual (PDF)
          </button>

          {/* GAP ANALYSIS CARDS */}
          <div className="flex flex-col gap-4">
             {/* Positive Highlight */}
             <div className={`p-4 rounded-lg border-l-4 shadow-sm ${fluencyDiff >= 0 ? 'bg-emerald-50 border-emerald-500' : 'bg-gray-50 border-gray-300'}`}>
                <div className="flex items-center justify-between mb-2">
                  <h4 className={`text-sm font-bold ${fluencyDiff >= 0 ? 'text-emerald-800' : 'text-gray-600'}`}>
                    Leitores Fluentes
                  </h4>
                  {fluencyDiff >= 0 ? <TrendingUp className="w-5 h-5 text-emerald-600" /> : <TrendingUp className="w-5 h-5 text-gray-400 rotate-180" />}
                </div>
                <p className="text-xs text-gray-600">
                  {fluencyDiff >= 0 
                    ? `A escola possui ${fluencyDiff.toFixed(1)}% a mais de fluência que a média municipal.` 
                    : `A escola está ${Math.abs(fluencyDiff).toFixed(1)}% abaixo da média municipal em fluência.`}
                </p>
             </div>

             {/* Critical Warning */}
             <div className={`p-4 rounded-lg border-l-4 shadow-sm ${criticalDiff > 0 ? 'bg-red-50 border-red-500' : 'bg-emerald-50 border-emerald-500'}`}>
                <div className="flex items-center justify-between mb-2">
                  <h4 className={`text-sm font-bold ${criticalDiff > 0 ? 'text-red-800' : 'text-emerald-800'}`}>
                    Níveis Críticos (N1+N2)
                  </h4>
                  {criticalDiff > 0 ? <AlertTriangle className="w-5 h-5 text-red-600" /> : <ShieldCheck className="w-5 h-5 text-emerald-600" />}
                </div>
                <p className="text-xs text-gray-600">
                  {criticalDiff > 0 
                    ? `Alerta: Índice de Nível 1 e 2 está ${criticalDiff.toFixed(1)}% superior à média da rede.` 
                    : `Excelente: Índice de Níveis 1 e 2 está ${Math.abs(criticalDiff).toFixed(1)}% inferior à média.`}
                </p>
             </div>
          </div>
        </div>

        {/* COMPARATIVE CHART */}
        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col">
          {/* HEADER WITH SELECTED SCHOOL HIGHLIGHT */}
          <div className="mb-6">
            <h3 className="text-lg font-bold text-gray-900 mb-4">Comparativo de Desempenho</h3>

            {/* Selected School Badge */}
            <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 flex items-start gap-3 mb-4">
              <div className="bg-blue-600 p-2 rounded-md shadow-sm">
                <School className="w-5 h-5 text-white" />
              </div>
              <div>
                <p className="text-xs font-bold text-blue-500 uppercase tracking-wider mb-0.5">Escola Selecionada</p>
                <h2 className="text-lg font-bold text-blue-900 leading-tight">{selectedSchool.name}</h2>
              </div>
            </div>

            <div className="flex justify-end items-center gap-4 text-xs mt-2">
              <div className="flex items-center gap-1.5"><div className="w-3 h-3 bg-gray-400 rounded-full"></div> Média Municipal</div>
              <div className="flex items-center gap-1.5"><div className="w-3 h-3 bg-blue-600 rounded-full border-2 border-white shadow-sm"></div> Escola Selecionada</div>
            </div>
          </div>

          <div className="flex-grow min-h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <LineChart data={chartData} margin={{ top: 20, right: 30, left: 10, bottom: 20 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f0f0f0" />
                <XAxis dataKey="name" tick={{fill: '#6b7280', fontSize: 12}} axisLine={false} tickLine={false} dy={10} />
                <YAxis unit="%" tick={{fill: '#6b7280', fontSize: 12}} axisLine={false} tickLine={false} />
                <Tooltip 
                  contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  formatter={(val: number) => [`${val.toFixed(1)}%`, '']}
                />
                {/* Municipal Average Line (Gray, Dashed or Solid thin) */}
                <Line type="monotone" dataKey="Municipal" stroke="#9ca3af" strokeWidth={2} dot={{r: 4, fill: '#9ca3af'}} />
                {/* Selected School Line (Blue/Neon, Thick) */}
                <Line type="monotone" dataKey="Escola" stroke="#2563eb" strokeWidth={3} dot={{r: 6, fill: '#2563eb', stroke: '#fff', strokeWidth: 2}} activeDot={{r: 8}} />
              </LineChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* DETAILED SCHOOL TABLE */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-gray-50">
          <div>
            <h3 className="text-lg font-bold text-gray-900">Tabela Geral de Escolas</h3>
            <p className="text-sm text-gray-500">Clique nos cabeçalhos para ordenar</p>
          </div>
          <div className="bg-white px-3 py-1 rounded-full border border-gray-200 text-xs font-medium text-gray-500 flex items-center gap-2">
            <Trophy className="w-3 h-3 text-yellow-500" />
            Ordenado por: {sortKey === 'ifl' ? 'IFL (Índice de Fluência)' : sortKey}
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-gray-500 uppercase bg-gray-100">
              <tr>
                <th 
                  className="px-4 py-3 cursor-pointer hover:bg-gray-200" 
                  onClick={() => handleSort('name')}
                >
                  Escola <ArrowUpDown className="w-3 h-3 inline ml-1" />
                </th>
                <th className="px-4 py-3 text-center">Previstos</th>
                <th className="px-4 py-3 text-center">Avaliados</th>
                <th 
                  className="px-4 py-3 text-center cursor-pointer hover:bg-gray-200"
                  onClick={() => handleSort('participation')}
                >
                  % Part. <ArrowUpDown className="w-3 h-3 inline ml-1" />
                </th>
                <th className="px-4 py-3 text-center bg-cyan-50">Pré-leitor (Total)</th>
                <th 
                  className="px-4 py-3 text-center bg-red-50 cursor-pointer hover:bg-red-100"
                  onClick={() => handleSort('n1n2')}
                >
                  Nível 1+2 <ArrowUpDown className="w-3 h-3 inline ml-1" />
                </th>
                <th className="px-4 py-3 text-center">Nível 3</th>
                <th className="px-4 py-3 text-center">Nível 4</th>
                <th className="px-4 py-3 text-center bg-blue-50">Iniciante</th>
                <th 
                  className="px-4 py-3 text-center bg-indigo-50 cursor-pointer hover:bg-indigo-100"
                  onClick={() => handleSort('fluent')}
                >
                  Fluente <ArrowUpDown className="w-3 h-3 inline ml-1" />
                </th>
                <th 
                  className="px-4 py-3 text-center bg-purple-50 cursor-pointer hover:bg-purple-100 font-bold"
                  onClick={() => handleSort('ifl')}
                >
                  IFL <ArrowUpDown className="w-3 h-3 inline ml-1" />
                </th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {sortedSchools.map((s) => {
                const ifl = calculateIFL(s);
                return (
                  <tr 
                    key={s.name} 
                    className={`hover:bg-gray-50 transition-colors cursor-pointer ${selectedSchoolId === s.name ? 'bg-blue-50 border-l-4 border-blue-500' : ''}`}
                    onClick={() => handleSelectSchool(s.name)}
                  >
                    <td className="px-4 py-3 font-medium text-gray-900 truncate max-w-[250px]" title={s.name}>
                      {s.name}
                    </td>
                    <td className="px-4 py-3 text-center text-gray-600">{s.predicted}</td>
                    <td className="px-4 py-3 text-center text-gray-600">{s.evaluated}</td>
                    <td className="px-4 py-3 text-center font-semibold text-gray-800">
                      {s.participation}%
                    </td>
                    <td className="px-4 py-3 text-center text-cyan-700 bg-cyan-50/30">{s.preReaderTotal.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center font-bold text-red-600 bg-red-50/30">
                      {(s.n1 + s.n2).toFixed(1)}%
                    </td>
                    <td className="px-4 py-3 text-center text-gray-500">{s.n3.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-gray-500">{s.n4.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-blue-700 bg-blue-50/30 font-medium">{s.beginner.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-indigo-700 bg-indigo-50/30 font-bold">{s.fluent.toFixed(1)}%</td>
                    <td className="px-4 py-3 text-center text-purple-700 bg-purple-50/30 font-extrabold">{ifl.toFixed(2)}</td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default SchoolPerformance;
